const result = [];

for (const item of $input.all()) {

  // 1. Create a safe, lowercase version of the keys
  const safeJson = {};
  for (const key in item.json) {
    const cleanKey = key.toLowerCase().replace(/[^a-z0-9]/g, '');
    safeJson[cleanKey] = item.json[key];
  }

  // 2. Clean up the budget text into a pure number
  const rawBudget = safeJson['estimatedbudget'] || 0;
  let cleanBudget = 0;
  if (typeof rawBudget === 'string') {
    cleanBudget = parseFloat(rawBudget.replace(/[^0-9.]/g, '')) || 0;
  } else {
    cleanBudget = Number(rawBudget) || 0;
  }

  // 3. Pack the data neatly into clientData and llmPrompt
  result.push({
    json: {
      clientData: {
        name: safeJson['name'] || '',
        email: safeJson['emailaddress'] || '',
        companyName: safeJson['companyorworkplacename'] || '',
        companySize: safeJson['companysize'] || 0,
        budget: cleanBudget
      },
      llmPrompt: {
        description: safeJson['description'] || '',
        budget: cleanBudget // Placed neatly inside the same folder!
      }
    }
  });
}

return result;

const result = [];

for (const item of $input.all()) {
  const rawText = item.json.output || '';
  let clientClassification = 'UNKNOWN';
  let justification = '';

  try {
    const cleanJsonString = rawText.replace(/```json/g, '').replace(/```/g, '').trim();
    const parsedAiData = JSON.parse(cleanJsonString);
    clientClassification = parsedAiData.client_classification || 'UNKNOWN';
    justification = parsedAiData.justification || '';
  } catch (error) {
    if (rawText.toLowerCase().includes('big client')) {
      clientClassification = 'BIG CLIENT';
    } else if (rawText.toLowerCase().includes('small client')) {
      clientClassification = 'SMALL CLIENT';
    }
    justification = rawText; 
  }

  // Safely grab the complete client details from the very first JS node
  const originalDetails = $node['seprate data']?.json?.clientData || {};
  const originalDescription = $node['seprate data']?.json?.llmPrompt?.description || '';

  // Output EVERYTHING side-by-side in one single row item
  result.push({
    json: {
      name: originalDetails.name || '',
      email: originalDetails.email || '',
      companyName: originalDetails.companyName || '',
      companySize: originalDetails.companySize || 0,
      budget: originalDetails.budget || 0,
      projectDescription: originalDescription,
      clientClassification: clientClassification,
      justification: justification
    }
  });
}

return result;
